from Crypto.Util.Padding import pad
from Crypto.Cipher import AES
from Crypto.Util.Padding import unpad
import binascii
import json


key = '091f457d59fb4fb901bac903d4728ceb'
def encrypt(data: str) -> str:
    try:
        # 转换字符串到字节
        data_bytes = data.encode('utf-8')
        key_bytes = bytes.fromhex(key)

        # 初始化加密器
        cipher = AES.new(key_bytes, AES.MODE_ECB)

        # 加密数据
        encrypted_data = cipher.encrypt(pad(data_bytes, AES.block_size))

        # 转为十六进制字符串
        return binascii.hexlify(encrypted_data).decode('utf-8').upper()
    except Exception as e:
        raise RuntimeError(e)



def decrypt(encrypted_data: str) :
    try:
        # 转换十六进制字符串到字节
        encrypted_data_bytes = bytes.fromhex(encrypted_data)
        key_bytes = bytes.fromhex(key)

        # 初始化解密器
        cipher = AES.new(key_bytes, AES.MODE_ECB)

        # 解密数据并去除填充
        decrypted_data = unpad(cipher.decrypt(encrypted_data_bytes), AES.block_size)

        # 转为字符串
        return decrypted_data.decode('utf-8')
    except Exception as e:
        raise RuntimeError(e)


